   339	    private static java.sql.Timestamp timestampFromLong(long millis) {
   340	        java.sql.Timestamp timestamp = new java.sql.Timestamp(millis);
   341	
   342	        // Must  account for negative millis < 1970
   343	        // Must account for the jdk millis bug where it does not set the nanos.
   344	        if ((millis % 1000) > 0) {
   345	            timestamp.setNanos((int) (millis % 1000) * 1000000);
   346	        } else if ((millis % 1000) < 0) {
   347	            timestamp.setNanos((int) (1000000000 - (Math.abs((millis % 1000) * 1000000))));
   348	        }
   349	        return timestamp;
   350	    }
