import java.time.LocalDate;
import java.util.*;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ProductCodec implements Codec<Product> {
  private static final Logger LOGGER = Logger.getLogger(ProductDBManager.class.getName());

  @Override
  public Product decode(BsonReader reader, DecoderContext context) {
    try {
      reader.readStartDocument();
      int id = 0;
      String name = null;
      BigDecimal price = null;
      LocalDate bestBefore = null;
      String category = null;
      int version = 0;
      List<Review> reviews = new ArrayList<>();

      while (reader.readBsonType() != BsonType.END_OF_DOCUMENT) {
        String fieldName = reader.readName();
        switch (fieldName) {
          case "_id" -> reader.readObjectId();
          case "id" -> id = reader.readInt32();
          case "name" -> name = reader.readString();
          case "price" -> price = BigDecimal.valueOf(reader.readDouble());
          case "bestBefore" -> {
            String bb = reader.readString();
            if (bb != null && bb.length() != 0) {
              bestBefore = LocalDate.parse(bb);
            }
          }
          case "category" -> category = reader.readString();
          case "version" -> version = reader.readInt32();
          case "reviews" -> {
            reader.readStartArray();
            while (reader.readBsonType() != BsonType.END_OF_DOCUMENT) {
              String review = null;
              int rating = 0;
              reader.readStartDocument();
              while (reader.readBsonType() != BsonType.END_OF_DOCUMENT) {
                String rFieldName = reader.readName();
                switch (rFieldName) {
                  case "review" -> review = reader.readString();
                  case "rating" -> rating = reader.readInt32();
                }
              }
              reader.readEndDocument();
              reviews.add(new Review(review, rating));
            }
            reader.readEndArray();
          }
        }
      }
      reader.readEndDocument();
      Product product = new Product(id, name, price, bestBefore, category, version);
      product.addReviews(reviews);
      return product;
    } catch (Exception e) {
      LOGGER.log(Level.SEVERE,"Error converting Bson into Product", e);
      throw e;
    }
  }

  @Override
  public void encode(BsonWriter writer, Product product, EncoderContext ctx) {
    try {
      writer.writeStartDocument();
      writer.writeInt32("id", product.getId());
      writer.writeString("name", product.getName());
      writer.writeDouble("price", product.getPrice().doubleValue());
      if (product.getBestBefore() != null) {
        writer.writeString("bestBefore", product.getBestBefore().toString());
      }
      writer.writeString("category", product.getCategory());
      writer.writeInt32("version", product.getVersion());
      List<Review> reviews = product.getReviews();
      if (reviews != null && reviews.size() != 0) {
        writer.writeStartArray("reviews");
        reviews.forEach(r -> {
          writer.writeStartDocument();
          writer.writeString("review", r.getReview());
          writer.writeInt32("rating", r.getRating());
          writer.writeEndDocument();
        });
        writer.writeEndArray();
      }
      writer.writeEndDocument();
    }catch (Exception e) {
      LOGGER.log(Level.SEVERE,"Error converting Product into Bson", e);
      throw e;
    }
  }

  @Override
  public Class<Product> getEncoderClass() {
    return Product.class;
  }
}
