package labs;

import io.helidon.dbclient.DbColumn;
import io.helidon.dbclient.DbMapper;
import io.helidon.dbclient.DbRow;
import org.bson.BsonType;
import org.bson.Document;
import org.bson.types.ObjectId;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.*;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ProductMapper implements DbMapper<Product> {
  private static final Logger LOGGER = Logger.getLogger(ProductMapper.class.getName());

  @Override
  public Product read(DbRow row) {
    try {
      Product product = new Product();
      row.forEach(column -> {
        String fieldName = column.name();
        switch (fieldName) {
          case "_id" -> column.get();
          case "id" -> product.setId(column.getInt());
          case "name" -> product.setName(column.getString());
          case "price" -> product.setPrice(BigDecimal.valueOf(column.getDouble()));
          case "bestBefore" -> {
            String bb = column.getString();
            if (bb != null && bb.length() != 0) {
              product.setBestBefore(LocalDate.parse(bb));
            }
          }
          case "category" -> product.setCategory(column.getString());
          case "version" -> product.setVersion(column.getInt());
          case "reviews" -> {
            DbColumn reviewsCol = row.column("reviews");
            if (reviewsCol != null) {
              List<Document> list = (List) reviewsCol.get();
              for (Document d : list) {
                String review = d.get("review", String.class);
                int rating = d.get("rating", Integer.class);
                product.addReview(new Review(review, rating));
              }
            }
          }
        }
      });
      return product;
    } catch (Exception e) {
      LOGGER.log(Level.SEVERE, "Error converting database row into product object", e);
      throw e;
    }
  }
  @Override
  public Map<String, ?> toNamedParameters(Product product) {
    Map<String,Object> map = new LinkedHashMap<>();
    map.put("id",product.getId());
    map.put("name",product.getName());
    map.put("price",product.getPrice().doubleValue());
    if (product.getBestBefore() != null) {
      map.put("bestBefore", product.getBestBefore().toString());
    }
    map.put("category",product.getCategory());
    map.put("version",product.getVersion());
    if (product.getReviews() != null) {
      map.put("reviews",product.getReviews());
    }
    System.out.println(map);
    return map;
  }
  @Override
  public List<?> toIndexedParameters(Product product) {
    List list = List.of(toNamedParameters(product).values());
    return list;
  }
}
