  public String findProducts() throws ProductException {
    try (MongoClient client = MongoClients.create(cStr)) {
      MongoDatabase db = client.getDatabase(cStr.getDatabase());
      MongoCollection<Document> col = db.getCollection("products");

      Bson proj = Projections.fields(
          Projections.include("id","name","price","bestBefore","category","version","reviews"),
          Projections.excludeId());
      StringBuffer result = new StringBuffer();
      try (MongoCursor<Document> cur = col.find().projection(proj).cursor()) {
        while(cur.hasNext()){
          Document d = cur.next();
          result.append(d.toJson()+"\n");
        }
      }
      if (result.length() == 0) {
        throw new ProductException("No products found");
      }
      return result.toString();
    }
