  public String findReviews(int rating) throws ProductException {
    try (MongoClient client = MongoClients.create(cStr)) {
      MongoDatabase db = client.getDatabase(cStr.getDatabase());
      MongoCollection<Document> col = db.getCollection("products");

      Bson proj = Projections.fields(
          Projections.include("reviews"),
          Projections.excludeId());
      Bson filters = Filters.elemMatch("reviews" , Filters.eq("rating" ,rating));

      StringBuffer result = new StringBuffer();
      try (MongoCursor<Document> cur = col.find().projection(proj).filter(filters).cursor()) {
        while (cur.hasNext()) {
          Document d = cur.next();
          result.append(d.toJson() + "\n");
        }
      }
      if (result.length() == 0) {
