  public void createProduct(String json) throws ProductException {
    try (MongoClient client = MongoClients.create(cStr)) {
      MongoDatabase db = client.getDatabase(cStr.getDatabase());
      MongoCollection<Document> col = db.getCollection("products");
      /*
      The org.bson.BsonDocument needs to be converted to org.bson.Document via using a codec.
      Default document codec org.bson.codecs.DocumentCodec is provided out of the box,
      but not automatically applied by the Bson API
      Same is true for the Document to BsonDocument conversion.
      https://stackoverflow.com/questions/49262903/mongodb-java-driver-convert-bsondocument-to-document-and-back
       */
      DocumentCodec codec = new DocumentCodec();
      DecoderContext decoderContext = DecoderContext.builder().build();
      Document doc = codec.decode(new BsonDocumentReader(BsonDocument.parse(json)), decoderContext);
      InsertOneResult r = col.insertOne(doc,new InsertOneOptions().bypassDocumentValidation(false));
      if (r.wasAcknowledged()) {
        LOGGER.log(Level.FINE, "Product inserted {0}", r.getInsertedId());
      }else{
        throw new ProductException("Product was not created");
      }
    } catch (MongoWriteException e) {
      if (e.getError().getCode() == 11000) {
        throw new ProductException("Product with this id already exists");
      }
      LOGGER.log(Level.SEVERE, "Error creating product", e);
    }
  }
