  public String updateProduct(int id, int version, String data) throws ProductException {
    try (MongoClient client = MongoClients.create(cStr)) {
      MongoDatabase db = client.getDatabase(cStr.getDatabase());
      MongoCollection<Document> col = db.getCollection("products");
      DocumentCodec codec = new DocumentCodec();
      DecoderContext decoderContext = DecoderContext.builder().build();
      Document json = codec.decode(new BsonDocumentReader(BsonDocument.parse(data)), decoderContext);
      Bson filters = Filters.and(Filters.eq("id", id),
                                 Filters.eq("version", version));
      List<Bson> fields = new ArrayList<>();
      for(String key : json.keySet()) {
        fields.add(Updates.set(key, json.get(key)));
      }
      fields.add(Updates.set("version", version+1));
      Bson values = Updates.combine(fields);

      FindOneAndUpdateOptions options = new FindOneAndUpdateOptions();
      options.returnDocument(ReturnDocument.AFTER);
      Document r = col.findOneAndUpdate(filters,values,options);
      return r.toJson();
    } catch (Exception e) {
      LOGGER.log(Level.SEVERE, "Error updating product", e);
      throw new ProductException("Error updating product");
    }
  }
