package io.helidon.dbclient.mongodb;

import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.CompletableFuture;

import io.helidon.common.mapper.MapperManager;
import io.helidon.dbclient.DbClientContext;
import io.helidon.dbclient.DbClientServiceContext;
import io.helidon.dbclient.DbExecuteContext;
import io.helidon.dbclient.DbMapper;
import io.helidon.dbclient.DbMapperManager;
import io.helidon.dbclient.DbRow;
import io.helidon.dbclient.DbStatementDml;
import io.helidon.dbclient.DbStatementType;
import io.helidon.dbclient.spi.DbMapperProvider;

public class DmlMapperRepro {
    record Product(int id, String name) {}

    static final class ProductMapper implements DbMapper<Product> {
        static int namedCalls;

        @Override
        public Product read(DbRow row) {
            throw new UnsupportedOperationException();
        }

        @Override
        public Map<String, ?> toNamedParameters(Product value) {
            namedCalls++;
            return Map.of("id", value.id(), "name", value.name());
        }

        @Override
        public List<?> toIndexedParameters(Product value) {
            return List.of(value.id(), value.name());
        }
    }

    static final class ProductMapperProvider implements DbMapperProvider {
        @SuppressWarnings("unchecked")
        @Override
        public <T> Optional<DbMapper<T>> mapper(Class<T> type) {
            return type == Product.class ? Optional.of((DbMapper<T>) new ProductMapper()) : Optional.empty();
        }
    }

    public static void main(String[] args) {
        DbMapperManager dbMapperManager = DbMapperManager.builder()
                .addMapperProvider(new ProductMapperProvider())
                .build();
        DbClientContext clientContext = DbClientContext.builder()
                .dbMapperManager(dbMapperManager)
                .mapperManager(MapperManager.builder().build())
                .clientServices(List.of())
                .dbType("mongoDb")
                .build();
        String statement = "{\"collection\":\"products\",\"operation\":\"insert\",\"value\":{\"id\":$id,\"name\":$name}}";
        DbExecuteContext execContext = DbExecuteContext.create("create-product", statement, clientContext);
        MongoDbStatementDml dml = new MongoDbStatementDml(null, DbStatementType.INSERT, execContext);
        dml.addParam("product", new Product(7, "tea"));
        DbClientServiceContext serviceContext = DbClientServiceContext.create(
                execContext,
                DbStatementType.INSERT,
                new CompletableFuture<>(),
                new CompletableFuture<>(),
                dml.parameters());
        String prepared = dml.prepareStatement(serviceContext);
        System.out.println("prepared=" + prepared);
        System.out.println("mapperCalls=" + ProductMapper.namedCalls);
        if (ProductMapper.namedCalls == 0 && prepared.contains("$id")) {
            System.out.println("REPRODUCED");
        } else {
            throw new IllegalStateException("Issue was not reproduced");
        }
    }
}
