/**
 * Expand named parameter values with matching {@link DbMapper} named parameter mappings.
 * Explicitly configured parameters take precedence over mapped values with the same name.
 *
 * @param parameters parameters to expand
 * @return original parameters or expanded copy
 */
protected Map<String, Object> mapNamedParameters(Map<String, Object> parameters) {
    Map<String, Object> mappedParameters = null;
    for (Object parameter : parameters.values()) {
        Map<String, ?> mapped = toNamedParameters(parameter);
        if (mapped != null && !mapped.isEmpty()) {
            if (mappedParameters == null) {
                mappedParameters = new HashMap<>(parameters);
            }
            mapped.forEach(mappedParameters::putIfAbsent);
        }
    }
    return mappedParameters == null ? parameters : mappedParameters;
}

/**
 * Expand indexed parameter values with matching {@link DbMapper} indexed parameter mappings.
 *
 * @param parameters parameters to expand
 * @return original parameters or expanded copy
 */
protected List<Object> mapIndexedParameters(List<Object> parameters) {
    List<Object> mappedParameters = null;
    int index = 0;
    for (Object parameter : parameters) {
        List<?> mapped = toIndexedParameters(parameter);
        if (mapped == null || mapped.isEmpty()) {
            if (mappedParameters != null) {
                mappedParameters.add(parameter);
            }
        } else {
            if (mappedParameters == null) {
                mappedParameters = new ArrayList<>(parameters.subList(0, index));
            }
            mappedParameters.addAll(mapped);
        }
        index++;
    }
    return mappedParameters == null ? parameters : mappedParameters;
}

@SuppressWarnings({"unchecked", "rawtypes"})
private Map<String, ?> toNamedParameters(Object parameter) {
    if (parameter == null) {
        return null;
    }
    Class<Object> parameterClass = (Class<Object>) parameter.getClass();
    DbMapperManager manager = context.dbMapperManager();
    if (manager instanceof DbMapperManagerImpl managerImpl) {
        return managerImpl.toNamedParametersIfPresent(parameter, parameterClass);
    }
    try {
        return manager.toNamedParameters(parameter, parameterClass);
    } catch (MapperException e) {
        if (isNoMapperFound(e)) {
            return null;
        }
        throw e;
    }
}

@SuppressWarnings({"unchecked", "rawtypes"})
private List<?> toIndexedParameters(Object parameter) {
    if (parameter == null) {
        return null;
    }
    Class<Object> parameterClass = (Class<Object>) parameter.getClass();
    DbMapperManager manager = context.dbMapperManager();
    if (manager instanceof DbMapperManagerImpl managerImpl) {
        return managerImpl.toIndexedParametersIfPresent(parameter, parameterClass);
    }
    try {
        return manager.toIndexedParameters(parameter, parameterClass);
    } catch (MapperException e) {
        if (isNoMapperFound(e)) {
            return null;
        }
        throw e;
    }
}

private static boolean isNoMapperFound(MapperException e) {
    String message = e.getMessage();
    return message != null && message.contains(DbMapperManagerImpl.ERROR_NO_MAPPER_FOUND);
}

